// scripts/fix-wrangler.mjs
// Patches the wrangler.json generated by @astrojs/cloudflare v13
// to be compatible with Cloudflare Pages deployment.
import { readFileSync, writeFileSync } from "node:fs";

const path = "./dist/server/wrangler.json";
const config = JSON.parse(readFileSync(path, "utf-8"));

// Fix 1: ASSETS is a reserved binding name in Pages
if (config.assets?.binding === "ASSETS") {
  config.assets.binding = "STATIC_ASSETS";
}

// Fix 2: triggers must have crons array, not empty object
if (config.triggers && typeof config.triggers === "object" && !Array.isArray(config.triggers.crons)) {
  config.triggers = { crons: [] };
}

// Fix 3: Remove SESSION kv binding with no id (sessions not used)
if (config.kv_namespaces) {
  config.kv_namespaces = config.kv_namespaces.filter(
    (kv) => kv.binding !== "SESSION" || kv.id
  );
}

// Fix 4: Remove fields that Pages wrangler doesn't understand
delete config.definedEnvironments;
delete config.secrets_store_secrets;
delete config.unsafe_hello_world;
delete config.worker_loaders;
delete config.ratelimits;
delete config.vpc_services;
delete config.python_modules;
if (config.dev) {
  delete config.dev.enable_containers;
  delete config.dev.generate_types;
}

writeFileSync(path, JSON.stringify(config, null, 2));
console.log("✓ Patched dist/server/wrangler.json for Cloudflare Pages compatibility");